	// If git is initialized and we're not using --no-git, create initial commit
	if te.GitInitialized && !hasNoGitFlag {
		cleanEnv := gitpkg.CleanEnv()
		te.CreateFile("README.md", "# Test Project")
		gitAdd := exec.Command("git", "add", ".")
		gitAdd.Dir = te.Dir

	for {
		candidate := ddxroot.InTree(current)
		if info, statErr := os.Stat(candidate); statErr == nil && info.IsDir() {
			return current
		}
		if current == gitRoot {
			break
		}
		parent := filepath.Dir(current)
		if parent == current {
			break // filesystem root — shouldn't happen if gitRoot is set
		}
		current = parent
	}
	return ""
}

// isExecuteBeadWorktree reports whether dir is inside an execute-bead
// workspace. Detects both linked worktrees and clone-backed attempt
// workspaces under the configured out-of-repo execution temp root. These
// are attempt-local repositories and must not be re-initialized.
func isExecuteBeadWorktree(dir string) bool {
	abs, err := filepath.Abs(dir)
	if err != nil {
		return false
	}
	slash := filepath.ToSlash(abs)
	// Legacy: a path component starting with .execute-bead-wt-.
	for _, part := range strings.Split(slash, "/") {
		if strings.HasPrefix(part, ".execute-bead-wt-") || strings.HasPrefix(part, ".execute-bead-clone-") {
			return true
		}
	}
	// Current: configured execution temp root.
	currentContainer := filepath.ToSlash(config.ExecutionTempRoot(""))
	if strings.HasPrefix(slash, currentContainer+"/") {
		return true
	}
	// Legacy fallback: older binaries always used $TMPDIR/ddx-exec-wt.
	legacyContainer := filepath.ToSlash(config.LegacyExecutionTempRoot())
	if strings.HasPrefix(slash, legacyContainer+"/") {
		return true
	}
	if override := os.Getenv("DDX_EXEC_WT_DIR"); override != "" {
		if strings.HasPrefix(slash, filepath.ToSlash(override)+"/") {
			return true
		}
	}
	return false
}

// AGENTS.md marker-delimited injection. Codex and other harnesses read
// AGENTS.md as primary guidance before work; users (and other tools) may
// add content of their own. We own only the content between markers —
// everything outside is preserved across re-runs of ddx init / ddx update.
const (
	agentsMarkerStart = "<!-- DDX-AGENTS:START -->"
	agentsMarkerEnd   = "<!-- DDX-AGENTS:END -->"
)

// ddxAgentsBlock returns the DDx-owned block that gets injected between
// markers. Harness-neutral — says "the `ddx` skill", not "/ddx" (which
// would only mean something to Claude Code).
func ddxAgentsBlock() string {
	return agentsMarkerStart + `
